import React from "react";
import styles from "./details.module.css";
import { useTranslation } from "react-i18next";

const Details: React.FC = () => {
  const [t] = useTranslation("global");

  return (
    <div className={styles.wrapper_details}>
      <p className={styles.text}>
        <strong className={styles.bold}>{t("product-details.details.wax.title")}</strong> {t("product-details.details.wax.desc")}
      </p>
      <p className={styles.text}>
        <strong className={styles.bold}>{t("product-details.details.fragrance.title")}</strong> Premium quality
        ingredients with natural essential oils{" "}
      </p>
      <div className={styles.wrapper_text}>
        <span className={styles.text}>
          <strong className={styles.bold}>{t("product-details.details.burning.title")}</strong> 70-75 hours
        </span>
        <span className={styles.text}>
          <strong className={styles.bold}>{t("product-details.details.wax.title")}</strong> 10cm x 5cm{" "}
        </span>
        <span className={styles.text}>
          <strong className={styles.bold}>Weight:</strong> 400g{" "}
        </span>
      </div>
    </div>
  );
};

export default Details;
